import React from "react";
import { FaBriefcase, FaUniversity, FaCloud } from "react-icons/fa";

const experienceData = [
  {
    title: "Senior Product Manager",
    company: "EY",
    date: "2022-Present",
    icon: <FaBriefcase />,
    type: "job",
  },
  {
    title: "Certified SAFe® 6 Product Owner/Product Manager",
    company: "Scaled Agile",
    date: "2024",
    icon: <FaUniversity />,
    type: "cert",
  },
  {
    title: "Certified Scrum Product Owner (CSPO)",
    company: "Scrum Alliance",
    date: "2022",
    icon: <FaUniversity />,
    type: "cert",
  },
  {
    title: "Senior Product Manager",
    company: "J.P. Morgan",
    date: "2021-2022",
    icon: <FaBriefcase />,
    type: "job",
  },
  {
    title: "Microsoft Certified: Azure Fundamentals",
    company: "Azure",
    date: "2021",
    icon: <FaCloud />,
    type: "cert",
  },
  {
    title: "Senior Product Manager",
    company: "ExxonMobil",
    date: "2014-2021",
    icon: <FaBriefcase />,
    type: "job",
  },
  {
    title: "PMI Agile Certified Practitioner (PMIACP)",
    company: "PMI",
    date: "2019",
    icon: <FaUniversity />,
    type: "cert",
  },
  {
    title: "Senior Product Owner",
    company: "ExxonMobil",
    date: "2013-2014",
    icon: <FaBriefcase />,
    type: "job",
  },
  {
    title: "Senior Scrum Master",
    company: "ExxonMobil",
    date: "2008-2013",
    icon: <FaBriefcase />,
    type: "job",
  },
  {
    title: "Supervisor",
    company: "IBM",
    date: "2001-2008",
    icon: <FaBriefcase />,
    type: "job",
  },
  {
    title: "Master of Systems Engineering",
    company: "Universidad Tecnologica Nacional (UTN)",
    date: "2001-2006",
    icon: <FaUniversity />,
    type: "edu",
  }
];

// Ordenar de más reciente a más viejo
experienceData.sort((a, b) => (b.date > a.date ? 1 : -1));

const ExperienceTimeline = () => {
  return (
    <div className="max-w-3xl mx-auto p-4">
      <div className="relative border-l-2 border-gray-300 ml-6">
        {experienceData.map((item, index) => (
          <div key={index} className="mb-8 pl-6 relative">
            <div className="absolute -left-4 top-1.5 bg-white border-2 border-gray-400 w-8 h-8 rounded-full flex items-center justify-center shadow-md">
              {item.icon}
            </div>
            <div
              className={`p-4 rounded-lg shadow-md ${
                item.type === "job"
                  ? "bg-gradient-to-r from-black via-gray-800 to-white text-white"
                  : "bg-gradient-to-r from-blue-600 via-blue-300 to-white text-black"
              }`}
            >
              <p className="text-xs text-gray-200 italic mb-1">{item.date}</p>
              <h3 className="text-base font-semibold">{item.title}</h3>
              <p className="text-sm">{item.company}</p>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default ExperienceTimeline;
